{"type":"user","message":{"role":"user","content":[{"tool_use_id":"tooluse_G9eiRv3NF5ytErJIAERvL4","type":"tool_result","content":"1\t#!/usr/bin/env python3\n2\t\"\"\"\n3\t识别创业板\"两阳夹一阴\"多方炮形态\n4\t\"\"\"\n5\timport akshare as ak\n6\timport pandas as pd\n7\tfrom datetime import datetime, timedelta\n8\timport warnings\n9\twarnings.filterwarnings('ignore')\n10\t\n11\tdef is_bullish_candle(open_price, close_price, prev_close, threshold=0.02):\n12\t    \"\"\"判断是否为阳线且涨幅>2%\"\"\"\n13\t    if close_price <= open_price:\n14\t        return False\n15\t    change_pct = (close_price - prev_close) / prev_close\n16\t    return change_pct > threshold\n17\t\n18\tdef is_bearish_candle(open_price, close_price, prev_close, threshold=0.01):\n19\t    \"\"\"判断是否为阴线且跌幅<1%\"\"\"\n20\t    if close_price >= open_price:\n21\t        return False\n22\t    change_pct = (close_price - prev_close) / prev_close\n23\t    return change_pct > -threshold\n24\t\n25\tdef check_engulfing(day2_open, day2_close, day3_open, day3_close):\n26\t    \"\"\"检查第3日阳线实体完全吞没第2日阴线\"\"\"\n27\t    # 第3日收盘价 > 第2日开盘价，第3日开盘价 < 第2日收盘价\n28\t    return day3_close > day2_open and day3_open < day2_close\n29\t\n30\tdef check_volume_increase(vol1, vol2, vol3):\n31\t    \"\"\"检查成交量逐步放大\"\"\"\n32\t    return vol2 > vol1 and vol3 > vol2\n33\t\n34\tdef check_ma_trend(df, idx):\n35\t    \"\"\"检查均线多头排列：5日均线 > 10日均线 > 20日均线\"\"\"\n36\t    if idx < 19:  # 需要至少20天数据计算20日均线\n37\t        return False\n38\t\n39\t    # 在第3天（idx+2）位置计算均线\n40\t    check_idx = idx + 2\n41\t    if check_idx >= len(df):\n42\t        return False\n43\t\n44\t    ma5 = df['收盘'].iloc[check_idx-4:check_idx+1].mean()\n45\t    ma10 = df['收盘'].iloc[check_idx-9:check_idx+1].mean()\n46\t    ma20 = df['收盘'].iloc[check_idx-19:check_idx+1].mean()\n47\t\n48\t    return ma5 > ma10 > ma20\n49\t\n50\tdef detect_bullish_sandwich(stock_code, end_date='2024-04-08'):\n51\t    \"\"\"检测单只股票的两阳夹一阴形态\"\"\"\n52\t    try:\n53\t        # 获取60日K线数据\n54\t        end_dt = datetime.strptime(end_d