l2, vol3):\n109\t                continue\n110\t\n111\t            # 条件4：形态出现在上升趋势中（均线多头排列）\n112\t            if not check_ma_trend(df, i):\n113\t                continue\n114\t\n115\t            # 计算成交量比\n116\t            vol_ratio_2_1 = vol2 / vol1\n117\t            vol_ratio_3_2 = vol3 / vol2\n118\t\n119\t            results.append({\n120\t                'code': stock_code,\n121\t                'date': day1['日期'].strftime('%Y-%m-%d'),\n122\t                'vol_ratio_2_1': vol_ratio_2_1,\n123\t                'vol_ratio_3_2': vol_ratio_3_2\n124\t            })\n125\t\n126\t        return results\n127\t\n128\t    except Exception as e:\n129\t        print(f\"处理 {stock_code} 时出错: {e}\")\n130\t        return []\n131\t\n132\tdef main():\n133\t    \"\"\"主函数\"\"\"\n134\t    print(\"开始获取创业板股票列表...\")\n135\t\n136\t    # 获取创业板股票列表（代码以300开头）\n137\t    try:\n138\t        stock_info = ak.stock_info_a_code_name()\n139\t        chinext_stocks = stock_info[stock_info['code'].str.startswith('300')]['code'].tolist()\n140\t        print(f\"找到 {len(chinext_stocks)} 只创业板股票\")\n141\t    except Exception as e:\n142\t        print(f\"获取股票列表失败: {e}\")\n143\t        return\n144\t\n145\t    all_results = []\n146\t\n147\t    # 遍历每只股票\n148\t    for idx, stock_code in enumerate(chinext_stocks[:50], 1):  # 限制处理数量以避免超时\n149\t        print(f\"处理 {idx}/{min(50, len(chinext_stocks))}: {stock_code}\")\n150\t        results = detect_bullish_sandwich(stock_code)\n151\t        all_results.extend(results)\n152\t\n153\t    # 写入结果文件\n154\t    output_file = '/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_22_bullish_sandwich/independent/claudecode/bullish_sandwich.txt'\n155\t\n156\t    with open(output_file, 'w', encoding='utf-8') as f:\n157\t        if all_results:\n158\t            for result in all_results:\n159\t                f.write(f\"{result['code']},{result['date']},{result['vol_ratio_2_1']:.2f},{result['vol_ratio_3_2']:.2f}\\n\")\